+                style.highlight(&active_count.to_string())
+            );
+            let confirmed = Confirm::new()
+                .with_prompt("Restart the daemon anyway?")
+                .default(false)
+                .interact()?;
+            if !confirmed {
+                println!("{} Aborted.", StatusIndicator::Info.display(style));
